/**
 * Builds a full Docusaurus config mirroring the root-directory template
 * (navbar from nav items, autogenerated per-label sidebars, blog, search,
 * sass, zooming, live-codeblock, mermaid, swizzled theme components).
 *
 * Consumers only need `docs.config.js` in their siteDir. All theme assets
 * (custom.scss, swizzled @theme/*, pages, static fallbacks) are shipped
 * inside this package and can be overridden by placing matching files in
 * the consumer's siteDir.
 */
const path = require('path');
const fs = require('fs');
const lightCodeTheme = require('prism-react-renderer').themes.github;
const darkCodeTheme = require('prism-react-renderer').themes.dracula;

/**
 * All packaged template assets live under `<pkg>/assets/`. A consumer can
 * override any of these files by placing a same-path copy in their siteDir:
 *   ASSETS.srcPages      <-> <siteDir>/src/pages/
 *   ASSETS.srcTheme      <-> <siteDir>/src/theme/
 *   ASSETS.srcComponents <-> <siteDir>/src/components/
 *   ASSETS.srcUtils      <-> <siteDir>/src/utils/
 *   ASSETS.srcCss        <-> <siteDir>/src/css/
 *   ASSETS.static        <-> <siteDir>/static/
 * See `mapPackageFallback` (which is derived from this same object) and the
 * `DocsResolvePlugin` for the runtime override logic.
 */
const ASSETS_DIR = path.resolve(__dirname, '..', 'assets');
const ASSETS = {
  dir: ASSETS_DIR,
  customCss: path.join(ASSETS_DIR, 'src', 'css', 'custom.scss'),
  static: path.join(ASSETS_DIR, 'static'),
  srcCss: path.join(ASSETS_DIR, 'src', 'css'),
  srcPages: path.join(ASSETS_DIR, 'src', 'pages'),
  srcTheme: path.join(ASSETS_DIR, 'src', 'theme'),
  srcComponents: path.join(ASSETS_DIR, 'src', 'components'),
  srcUtils: path.join(ASSETS_DIR, 'src', 'utils'),
};

/**
 * Single source of truth mapping `@site/<path>` sub-roots to their packaged
 * fallback directories. Both `mapPackageFallback` (used by the resolver
 * plugin) and callers that need to know a concrete packaged directory should
 * read from this table.
 */
const SRC_BUCKETS = {
  components: ASSETS.srcComponents,
  utils: ASSETS.srcUtils,
  theme: ASSETS.srcTheme,
  pages: ASSETS.srcPages,
  css: ASSETS.srcCss,
};

/**
 * Build a map of `@theme/<component>` → packaged-file aliases for every theme
 * component shipped by this package, skipping any that the consumer has
 * overridden in `<siteDir>/src/theme/`.
 *
 * We intentionally do NOT use a Docusaurus `getThemePath()` plugin here:
 * Docusaurus treats plugin theme paths as "parent" themes and registers both
 * `@theme/<name>` → file AND `@theme-original/<name>` → the same file. Since
 * our wrappers import `@theme-original/<name>` to delegate to the previous
 * theme (`@docusaurus/theme-classic`), binding `@theme-original` to our own
 * wrapper creates infinite recursion at render time.
 *
 * Instead we register `@theme/<name>` aliases via `configureWebpack`, which
 * runs AFTER the base config is built. This lets us override theme-classic's
 * `@theme/<name>` without touching `@theme-original/<name>` (which still
 * points at theme-classic). Consumer overrides at `<siteDir>/src/theme/<name>`
 * are already registered by Docusaurus as user theme aliases, so we skip
 * writing an alias for those files and the consumer's version wins.
 */
function buildThemeAliasMap({ siteDir }) {
  const alias = {};
  if (!fs.existsSync(ASSETS.srcTheme)) return alias;
  const stripExt = (p) => p.replace(/\.(ts|tsx|js|jsx|mjs|cjs)$/i, '');
  for (const absFile of walkFiles(ASSETS.srcTheme)) {
    if (!/\.(ts|tsx|js|jsx|mjs|cjs)$/i.test(absFile)) continue;
    const relFromPkg = path.relative(ASSETS.srcTheme, absFile);
    const userFile = path.join(siteDir, 'src', 'theme', relFromPkg);
    if (fs.existsSync(userFile)) continue;
    const relNoExt = stripExt(relFromPkg).split(path.sep).join('/');
    // `@theme/<name>/index` collapses to `@theme/<name>` for imports.
    const key = relNoExt.replace(/\/index$/i, '');
    alias['@theme/' + key] = absFile;
  }
  return alias;
}

/**
 * Recursively walk a directory and yield every regular file (absolute path).
 */
function walkFiles(root) {
  const out = [];
  if (!fs.existsSync(root)) return out;
  const stack = [root];
  while (stack.length) {
    const dir = stack.pop();
    for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
      const full = path.join(dir, entry.name);
      if (entry.isDirectory()) stack.push(full);
      else if (entry.isFile()) out.push(full);
    }
  }
  return out;
}

/**
 * For a request of the form `@site/<subpath>`, return the package's fallback
 * absolute path if that subpath is one we back-fill, else null.
 *
 * Mapping:
 *   @site/src/components/...  → <pkg>/assets/src/components/...
 *   @site/src/utils/...       → <pkg>/assets/src/utils/...
 *   @site/src/theme/...       → <pkg>/assets/src/theme/...
 *   @site/src/pages/...       → <pkg>/assets/src/pages/...
 *   @site/src/css/...         → <pkg>/assets/src/css/...   (only `custom.scss` ships today)
 *   @site/static/...          → <pkg>/assets/static/...
 */
function mapPackageFallback(rel) {
  const segs = rel.split('/');
  if (segs[0] === 'src' && segs.length >= 3) {
    const bucketRoot = SRC_BUCKETS[segs[1]];
    if (!bucketRoot) return null;
    return path.join(bucketRoot, segs.slice(2).join('/'));
  }
  if (segs[0] === 'static' && segs.length >= 2) {
    return path.join(ASSETS.static, segs.slice(1).join('/'));
  }
  return null;
}

/**
 * Webpack resolver plugin that back-fills `@site/src/...` and `@site/static/...`
 * from the package's shipped assets when the consumer hasn't provided their own.
 *
 * Docusaurus registers `@site` → siteDir as a standard webpack alias. Adding an
 * additional exact-match alias does not reliably win: enhanced-resolve's
 * AliasPlugin short-circuits on the first matching entry rather than falling
 * through to later matches, so the default `@site` prefix alias always wins.
 *
 * Instead we install a resolver plugin that runs on the `described-resolve`
 * hook (same hook AliasPlugin uses) and rewrites the request BEFORE any alias
 * fires: we check if the user has an override under `<siteDir>/<rel>`; if so
 * we do nothing (the default alias handles it). Otherwise we rewrite the
 * request to the absolute path inside the package's assets directory.
 */
class DocsResolvePlugin {
  constructor({ siteDir }) {
    this.siteDir = siteDir;
    this.userCache = new Map();
  }
  userHasOverride(rel) {
    if (this.userCache.has(rel)) return this.userCache.get(rel);
    const base = path.join(this.siteDir, rel);
    const candidates = [
      base,
      base + '.ts',
      base + '.tsx',
      base + '.js',
      base + '.jsx',
      base + '.mjs',
      base + '.cjs',
      base + '.css',
      base + '.scss',
      base + '.sass',
      path.join(base, 'index.ts'),
      path.join(base, 'index.tsx'),
      path.join(base, 'index.js'),
      path.join(base, 'index.jsx'),
    ];
    const has = candidates.some((c) => {
      try {
        return fs.statSync(c).isFile();
      } catch {
        return false;
      }
    });
    this.userCache.set(rel, has);
    return has;
  }
  apply(resolver) {
    const target = resolver.ensureHook('resolve');
    resolver.getHook('described-resolve').tapAsync(
      'DocsResolvePlugin',
      (request, resolveContext, callback) => {
        const req = request.request;
        if (typeof req !== 'string' || !req.startsWith('@site/')) {
          return callback();
        }
        const rel = req.slice('@site/'.length);
        const pkgAbs = mapPackageFallback(rel);
        if (!pkgAbs) return callback();
        if (this.userHasOverride(rel)) return callback();
        if (process.env.BNDY_DOCS_DEBUG) {
          console.log('[@bndynet/docs] rewrite', req, '→', pkgAbs);
        }
        const newRequest = { ...request, request: pkgAbs };
        return resolver.doResolve(
          target,
          newRequest,
          '@bndynet/docs site override: ' + pkgAbs,
          resolveContext,
          callback,
        );
      },
    );
  }
}

/**
 * In a consumer setup, `@bndynet/docs` is a real npm install and its shipped
 * theme swizzles/pages live at
 *   <siteDir>/node_modules/@bndynet/docs/assets/src/...
 * Docusaurus's default `babel-loader` rule has `exclude: /node_modules/`, so
 * those TSX/JSX files never get transpiled and webpack emits the classic
 *   "Module parse failed: Unexpected token ... no loaders are configured to
 *    process this file type"
 * against our `@theme/ColorModeToggle` et al.
 *
 * Fix: register a sibling rule that applies Docusaurus's own JS loader (same
 * babel config as the core rule) to files under our assets directory.
 *
 * The rule is only emitted when ASSETS.dir actually sits inside
 * `node_modules/` (i.e., consumer mode). In a workspaces / symlinked monorepo
 * setup the real path is a subdirectory of the siteDir and already matches
 * the default rule; adding this would cause every asset file to be
 * double-transpiled.
 */
const ASSETS_IN_NODE_MODULES = ASSETS.dir
  .split(path.sep)
  .includes('node_modules');

/**
 * `@docusaurus/theme-mermaid@3.10.x` treats `@mermaid-js/layout-elk` as an
 * optional peer dependency: it probes availability at config time and feeds
 * `DefinePlugin({__DOCUSAURUS_MERMAID_LAYOUT_ELK_ENABLED__: <bool>})` so the
 * dynamic `await import('@mermaid-js/layout-elk')` inside the theme's
 * `loadMermaid.js` becomes dead code when the package is not installed.
 *
 * In practice webpack 5.106+ does not reliably tree-shake that dead branch
 * for consumer-mode installs and fails the client build with:
 *   "Module not found: Error: Can't resolve '@mermaid-js/layout-elk'
 *    in '.../node_modules/@docusaurus/theme-mermaid/lib/client'".
 * We install a `resolve.alias` -> false stub *only when the package isn't
 * resolvable*, matching theme-mermaid's own detection logic so we never
 * clobber a real installation. The alias returns an empty module that the
 * (also dead) `__DOCUSAURUS_MERMAID_LAYOUT_ELK_ENABLED__` guard never reaches.
 *
 * TODO(docusaurus-3.10.x): drop once webpack reliably tree-shakes the dead
 * import, or once theme-mermaid guards the import site (not just the call
 * site) against missing packages.
 */
function isLayoutElkResolvable(siteDir) {
  try {
    require.resolve('@mermaid-js/layout-elk', { paths: [siteDir] });
    return true;
  } catch {
    return false;
  }
}

function docsAliasPlugin({ siteDir }) {
  const themeAlias = buildThemeAliasMap({ siteDir });
  const layoutElkResolvable = isLayoutElkResolvable(siteDir);
  return {
    name: '@bndynet/docs-alias',
    configureWebpack(_config, isServer, utils) {
      const extraRules = [];
      if (ASSETS_IN_NODE_MODULES && utils && typeof utils.getJSLoader === 'function') {
        extraRules.push({
          test: /\.(j|t)sx?$/,
          include: [ASSETS.dir],
          use: [utils.getJSLoader({ isServer })],
        });
      }
      const alias = { ...themeAlias };
      if (!layoutElkResolvable) {
        // TODO(docusaurus-3.10.x): see isLayoutElkResolvable comment above.
        alias['@mermaid-js/layout-elk'] = false;
      }
      return {
        resolve: {
          alias,
          plugins: [new DocsResolvePlugin({ siteDir })],
        },
        ...(extraRules.length ? { module: { rules: extraRules } } : {}),
      };
    },
  };
}

function buildDocusaurusConfig({ siteDir, app, docsPathRelative, blog, site }) {
  const t = site.theme || {};

  // customCss: user override, else shipped default.
  const userScss = path.join(siteDir, 'src', 'css', 'custom.scss');
  const customCss = fs.existsSync(userScss) ? userScss : ASSETS.customCss;

  // staticDirectories: user first, package fallback. Explicit list required
  // because we may include absolute paths outside siteDir.
  const userStatic = path.join(siteDir, 'static');
  const staticDirectories = [];
  if (Array.isArray(app.staticDirectories) && app.staticDirectories.length) {
    for (const d of app.staticDirectories) {
      staticDirectories.push(path.isAbsolute(d) ? d : path.join(siteDir, d));
    }
  } else if (fs.existsSync(userStatic)) {
    staticDirectories.push(userStatic);
  }
  if (fs.existsSync(ASSETS.static)) staticDirectories.push(ASSETS.static);

  // Pages path: prefer user's src/pages, else shipped defaults.
  const userPages = path.join(siteDir, 'src', 'pages');
  const pagesPath = fs.existsSync(userPages) ? userPages : ASSETS.srcPages;

  // clientModules: allow consumer's static/app.js to run on boot; else use shipped one.
  const clientModules = [];
  const userAppJs = path.join(siteDir, 'static', 'app.js');
  const pkgAppJs = path.join(ASSETS.static, 'app.js');
  if (fs.existsSync(userAppJs)) {
    clientModules.push('./' + path.relative(siteDir, userAppJs).split(path.sep).join('/'));
  } else if (fs.existsSync(pkgAppJs)) {
    clientModules.push(pkgAppJs);
  }

  // Global scripts from the packaged static/.
  // `app.js` (registered above as a client module) depends on globals defined
  // in `script.js` (e.g. `appendThemeForIframes`, `getCurrentTheme`). These
  // must be loaded as classic <script> tags, not ES modules, which is what
  // Docusaurus's `scripts:` config does. The file is served at
  // `<baseUrl>script.js` from either the consumer's `static/script.js` (if
  // provided) or the package's shipped copy (via `staticDirectories`).
  const baseUrl = typeof app.baseUrl === 'string' && app.baseUrl ? app.baseUrl : '/';
  const normBase = baseUrl.endsWith('/') ? baseUrl : baseUrl + '/';
  // Rewrite baseUrl-relative script URLs (e.g. "/tw.config.js") so a single
  // `externalScripts` list works under any baseUrl. External URLs (http/https/
  // protocol-relative "//") and already baseUrl-prefixed strings pass through.
  const prefixWithBaseUrl = (src) => {
    if (typeof src !== 'string' || src.length === 0) return src;
    if (/^(https?:)?\/\//i.test(src)) return src;
    if (!src.startsWith('/')) return src;
    if (normBase !== '/' && src.startsWith(normBase)) return src;
    return normBase + src.replace(/^\/+/, '');
  };
  const rewriteEntry = (s) => {
    if (typeof s === 'string') return prefixWithBaseUrl(s);
    if (s && typeof s === 'object' && typeof s.src === 'string') {
      return { ...s, src: prefixWithBaseUrl(s.src) };
    }
    return s;
  };

  const pkgStaticScripts = [];
  const userScriptJs = path.join(siteDir, 'static', 'script.js');
  const pkgScriptJs = path.join(ASSETS.static, 'script.js');
  if (fs.existsSync(userScriptJs) || fs.existsSync(pkgScriptJs)) {
    pkgStaticScripts.push(normBase + 'script.js');
  }
  const userScripts = (Array.isArray(app.externalScripts) ? app.externalScripts : []).map(
    rewriteEntry,
  );
  // De-dupe: user-provided entry for the same URL wins (keep user's object form).
  const userScriptUrls = new Set(
    userScripts.map((s) => (typeof s === 'string' ? s : s && s.src)).filter(Boolean),
  );
  const mergedScripts = [
    ...pkgStaticScripts.filter((s) => !userScriptUrls.has(s)),
    ...userScripts,
  ];

  const userStylesheets = (Array.isArray(app.externalStylesheets) ? app.externalStylesheets : []).map(
    rewriteEntry,
  );

  const liveCodeBlock = t.liveCodeBlock || { playgroundPosition: 'top' };
  const imageZoom = t.imageZoom || { selector: '.markdown img' };
  const metadata = Array.isArray(t.metadata) && t.metadata.length
    ? t.metadata
    : [{ name: 'keywords', content: 'documentation' }];

  const docsRouteBasePath = typeof site.docsRouteBasePath === 'string'
    ? site.docsRouteBasePath
    : 'docs';

  const defaultBlogSidebarTitle = 'All posts';
  const blogSidebarTitle =
    typeof site.blogSidebarTitle === 'string' && site.blogSidebarTitle.trim()
      ? site.blogSidebarTitle.trim()
      : defaultBlogSidebarTitle;

  // Rewrite a siteDir-relative asset path (e.g. `'img/hero.jpg'`) with the
  // current baseUrl so the same config works under `/` and `/project-name/`
  // deploys. Absolute/protocol-relative URLs pass through untouched.
  const resolveAssetUrl = (src) => {
    if (typeof src !== 'string' || src.length === 0) return src;
    if (/^(https?:)?\/\//i.test(src)) return src;
    return prefixWithBaseUrl(src.startsWith('/') ? src : '/' + src);
  };

  // Expose a small set of user-provided values to runtime React via
  // `useDocusaurusContext().siteConfig.customFields`. Homepage/features
  // components read these so the same packaged pages adapt to any siteDir.
  //
  // `hero.background.image` is rewritten through `resolveAssetUrl` so an
  // author can write `image: 'img/hero.jpg'` once and have it resolve under
  // any baseUrl (root deploys and project-pages deploys both work).
  const heroForRuntime = app.hero
    ? {
        ...app.hero,
        background: app.hero.background
          ? {
              ...app.hero.background,
              image: resolveAssetUrl(app.hero.background.image),
            }
          : undefined,
      }
    : undefined;
  const customFields = {
    docsRouteBasePath,
    hero: heroForRuntime,
  };

  return {
    title: app.title,
    tagline: app.tagline,
    favicon: t.favicon || 'img/favicon.ico',
    staticDirectories,

    url: app.url,
    baseUrl: app.baseUrl,

    onBrokenLinks: 'log',
    customFields,

    i18n: {
      defaultLocale: 'en',
      locales: ['en'],
    },

    markdown: {
      mermaid: true,
    },

    presets: [
      [
        'classic',
        /** @type {import('@docusaurus/preset-classic').Options} */
        ({
          docs: {
            path: docsPathRelative,
            routeBasePath: docsRouteBasePath,
            sidebarPath: path.join(__dirname, 'sidebars.cjs'),
          },
          blog: blog
            ? {
                showReadingTime: true,
                /** List every post in the blog sidebar (default Docusaurus is 5 + "Recent posts"). */
                blogSidebarCount: 'ALL',
                blogSidebarTitle,
              }
            : false,
          pages: {
            path: pagesPath,
          },
          theme: {
            customCss,
          },
        }),
      ],
    ],

    themeConfig: {
      image: t.image || 'img/docusaurus-social-card.jpg',
      metadata,
      navbar: {
        title: app.name,
        ...(app.logoUrl ? { logo: { alt: app.title, src: app.logoUrl } } : {}),
        items: app.menus,
      },
      footer: {
        style: site.footer?.style || 'dark',
        links: app.footerLinks,
        copyright: app.copyright,
      },
      prism: {
        theme: t.prism?.light || lightCodeTheme,
        darkTheme: t.prism?.dark || darkCodeTheme,
        magicComments: t.prism?.magicComments || [
          {
            className: 'theme-code-block-highlighted-line',
            line: 'highlight-next-line',
            block: { start: 'highlight-start', end: 'highlight-end' },
          },
          {
            className: 'code-block-error-line',
            line: 'This will error',
          },
        ],
      },
      imageZoom,
      liveCodeBlock,
    },

    themes: ['@docusaurus/theme-live-codeblock', '@docusaurus/theme-mermaid'],

    plugins: [
      'docusaurus-plugin-zooming',
      'docusaurus-plugin-sass',
      [
        '@easyops-cn/docusaurus-search-local',
        { hashed: true, indexPages: true },
      ],
      () => docsAliasPlugin({ siteDir }),
    ],

    stylesheets: userStylesheets,
    scripts: mergedScripts,

    clientModules,
  };
}

module.exports = { buildDocusaurusConfig };
